25	test("natural language generation creates a draft skill with source 在线编写", () => {
26	  const skill = createSkillFromNaturalLanguage("创建客服质检技能，按对话输出扣分项、证据句和改进建议");
27	
28	  assert.equal(skill.source, "在线编写");
29	  assert.equal(skill.status, "草稿");
30	  assert.match(skill.skillId, /^[a-z0-9_-]{3,64}$/);
31	  assert.ok(skill.assets.includes("SKILL.md"));
32	  assert.ok(skill.assets.includes("manifest.json"));
33	  assert.ok(skill.content.includes("/when_to_use"));
34	  assert.ok(skill.content.includes("/constraints"));
35	  assert.ok(skill.files, "should have files property");
36	  assert.ok(skill.files["SKILL.md"], "should have SKILL.md in files");
37	  assert.ok(skill.files["manifest.json"], "should have manifest.json in files");
38	  assert.ok(skill.files["input.schema.json"], "should have input.schema.json in files");
39	  assert.ok(skill.files["output.schema.json"], "should have output.schema.json in files");
40	  assert.equal(skill.files["SKILL.md"], skill.content, "files.SKILL.md should equal content");
41	});
