43	test("bundleFileTemplate returns correct default content for each file type", () => {
44	  const skillMd = bundleFileTemplate("SKILL.md");
45	  assert.ok(skillMd.includes("/when_to_use"));
46	  assert.ok(skillMd.includes("/input"));
47	  assert.ok(skillMd.includes("/output"));
48	  assert.ok(skillMd.includes("/constraints"));
49	
50	  const manifest = bundleFileTemplate("manifest.json");
51	  const parsed = JSON.parse(manifest);
52	  assert.equal(parsed.name, "技能名称");
53	  assert.equal(parsed.entry, "SKILL.md");
54	  assert.ok(parsed.schemas.input);
55	
56	  const inputSchema = bundleFileTemplate("input.schema.json");
57	  assert.ok(inputSchema.includes("user_query"));
58	  assert.ok(inputSchema.includes("json-schema.org"));
59	
60	  const outputSchema = bundleFileTemplate("output.schema.json");
61	  assert.ok(outputSchema.includes("conclusion"));
62	
63	  const emptyJson = bundleFileTemplate("custom.json");
64	  assert.equal(emptyJson, "{}");
65	
66	  const emptyYaml = bundleFileTemplate("custom.yaml");
67	  assert.equal(emptyYaml, "");
68	
69	  const emptyYml = bundleFileTemplate("custom.yml");
70	  assert.equal(emptyYml, "");
71	
72	  const byPath = bundleFileTemplate("schemas/input.schema.json");
73	  assert.ok(byPath.includes("user_query"), "basename matching works for paths");
74	
75	  const fallback = bundleFileTemplate("custom.py");
76	  assert.equal(fallback, "");
77	});
