79	test("validateSkillId rejects invalid inputs and accepts valid ones", () => {
80	  // too short
81	  assert.equal(validateSkillId("ab").valid, false);
82	  assert.ok(validateSkillId("ab").error);
83	  // too long
84	  assert.equal(validateSkillId("a".repeat(65)).valid, false);
85	  // invalid characters
86	  assert.equal(validateSkillId("Hello World").valid, false);
87	  assert.equal(validateSkillId("my_skill!").valid, false);
88	  assert.equal(validateSkillId("UPPERCASE").valid, false);
89	  // duplicate
90	  assert.equal(validateSkillId("customer_service_qa", ["customer_service_qa"]).valid, false);
91	  // valid
92	  assert.equal(validateSkillId("my_skill").valid, true);
93	  assert.equal(validateSkillId("valid-id-123").valid, true);
94	  assert.equal(validateSkillId("a0b").valid, true);
95	  assert.equal(validateSkillId("customer_service_qa", ["other_skill"]).valid, true);
96	});
