98	test("validatePublishReady checks required declaration blocks", () => {
99	  const full = { content: "/when_to_use\n/input\n/output\n/constraints" };
100	  assert.equal(validatePublishReady(full).ready, true);
101	  assert.deepEqual(validatePublishReady(full).missing, []);
102	
103	  const partial = { content: "/when_to_use\n/input" };
104	  assert.equal(validatePublishReady(partial).ready, false);
105	  assert.deepEqual(validatePublishReady(partial).missing, ["/output", "/constraints"]);
106	
107	  const empty = { content: "" };
108	  assert.equal(validatePublishReady(empty).ready, false);
109	  assert.deepEqual(validatePublishReady(empty).missing, ["/when_to_use", "/input", "/output", "/constraints"]);
110	
111	  // Should also work with files-based skills
112	  const filesFull = { files: { "SKILL.md": "/when_to_use\n/input\n/output\n/constraints" }, content: "" };
113	  assert.equal(validatePublishReady(filesFull).ready, true, "should read from files['SKILL.md']");
114	
115	  const filesPartial = { files: { "SKILL.md": "/when_to_use\n/input" } };
116	  assert.equal(validatePublishReady(filesPartial).ready, false, "should detect missing blocks from files");
117	  assert.deepEqual(validatePublishReady(filesPartial).missing, ["/output", "/constraints"]);
118	});
