120	test("validateImportFile rejects dangerous or unsupported files", () => {
121	  // allowed formats
122	  assert.deepEqual(validateImportFile("skill.md", 1000), { valid: true, error: "" });
123	  assert.deepEqual(validateImportFile("skill.json", 1000), { valid: true, error: "" });
124	  assert.deepEqual(validateImportFile("skill.yaml", 1000), { valid: true, error: "" });
125	  assert.deepEqual(validateImportFile("skill.zip", 1000), { valid: true, error: "" });
126	
127	  // dangerous formats
128	  assert.equal(validateImportFile("script.sh", 1000).valid, false);
129	  assert.equal(validateImportFile("program.exe", 1000).valid, false);
130	  assert.equal(validateImportFile("script.py", 1000).valid, false);
131	
132	  // unsupported format
133	  assert.equal(validateImportFile("data.csv", 1000).valid, false);
134	  assert.equal(validateImportFile("doc.pdf", 1000).valid, false);
135	
136	  // oversized
137	  assert.equal(validateImportFile("large.zip", 11 * 1024 * 1024).valid, false);
138	});
