171	test("publish request enters security review and scan pass auto publishes", () => {
172	  assert.equal(getNextStatus("草稿", "request_publish"), "扫描中");
173	  assert.equal(getNextStatus("扫描失败", "request_publish"), "扫描中");
174	  assert.equal(getNextStatus("已下架", "request_publish"), "扫描中");
175	  assert.equal(getNextStatus("扫描中", "scan_pass"), "已发布");
176	  assert.equal(getNextStatus("扫描中", "scan_fail"), "扫描失败");
177	  assert.equal(getNextStatus("已发布", "unpublish"), "已下架");
178	  assert.throws(() => getNextStatus("草稿", "publish"), /不允许/);
179	  assert.throws(() => getNextStatus("已发布", "request_publish"), /不允许/);
180	});
