5	const DEFAULT_SKILL_MD = `/when_to_use
6	当用户需要[描述场景]时使用。
7	
8	/input
9	required:
10	  - user_query: 用户当前问题或任务目标
11	optional:
12	  - context: 对话上下文
13	missing_input_strategy: ask_user
14	
15	/output
16	format: markdown
17	structure:
18	  - conclusion: 结论
19	  - steps: 执行步骤
20	  - next_actions: 下一步建议
21	
22	/constraints
23	- 不得编造未在输入或参考资料中出现的信息
24	- 依据不足时必须明确说明需要补充信息`;
