26	export function bundleFileTemplate(filename) {
27	  const name = String(filename || "").toLowerCase();
28	  const basename = name.split("/").pop();
29	  if (basename === "skil.md" || basename === "skill.md") {
30	    return DEFAULT_SKILL_MD;
31	  }
32	  if (basename === "manifest.json") {
33	    return JSON.stringify({
34	      name: "技能名称",
35	      skill_id: "skill_id_placeholder",
36	      version: "0.1.0",
37	      entry: "SKILL.md",
38	      language: "zh-CN",
39	      license: "MIT",
40	      schemas: { input: "input.schema.json", output: "output.schema.json" },
41	      dependencies: [],
42	      scripts: {},
43	      tags: []
44	    }, null, 2);
45	  }
46	  if (basename === "input.schema.json") {
47	    return JSON.stringify({
48	      "$schema": "https://json-schema.org/draft/2020-12/schema",
49	      title: "输入参数",
50	      type: "object",
51	      required: ["user_query"],
52	      properties: {
53	        user_query: { type: "string", description: "用户当前问题或任务目标" },
54	        context: { type: "string", description: "对话上下文" }
55	      }
56	    }, null, 2);
57	  }
58	  if (basename === "output.schema.json") {
59	    return JSON.stringify({
60	      "$schema": "https://json-schema.org/draft/2020-12/schema",
61	      title: "输出结构",
62	      type: "object",
63	      required: ["conclusion"],
64	      properties: {
65	        conclusion: { type: "string", description: "结论" },
66	        steps: { type: "array", description: "执行步骤" },
67	        next_actions: { type: "array", description: "下一步建议" }
68	      }
69	    }, null, 2);
70	  }
71	  if (name.endsWith(".json")) return "{}";
72	  if (name.endsWith(".yaml") || name.endsWith(".yml")) return "";
73	  return "";
74	}
