239	export function slugifySkillId(text) {
240	  const normalized = text
241	    .toLowerCase()
242	    .replace(/客服/g, "customer_service")
243	    .replace(/质检/g, "qa")
244	    .replace(/政策/g, "policy")
245	    .replace(/合同/g, "contract")
246	    .replace(/会议/g, "meeting")
247	    .replace(/技能/g, "skill")
248	    .replace(/[^a-z0-9_-]+/g, "_")
249	    .replace(/^_+|_+$/g, "")
250	    .replace(/_+/g, "_");
251	  return (normalized || "generated_skill").slice(0, 64);
252	}
