254	export function createSkillFromNaturalLanguage(prompt) {
255	  const text = String(prompt || "").trim();
256	  const isQa = /质检|客服/.test(text);
257	  const isPolicy = /政策|条款|制度/.test(text);
258	  const isContract = /合同|风险|法务/.test(text);
259	  const name = isQa ? "客服质检助手" : isPolicy ? "政策问答 Skill" : isContract ? "合同风险审阅" : "业务流程助手";
260	  const skillId = slugifySkillId(`${name}_${Date.now().toString(36)}`);
261	  const output = isQa ? "score、issues、suggestions" : isPolicy ? "conclusion、reason、evidence、next_steps" : "conclusion、steps、risks、next_actions";
262	  return {
263	    id: `sk-${Date.now()}`,
264	    name,
265	    skillId,
266	    description: text || "基于自然语言描述生成的 Skill 草稿。",
267	    source: "在线编写",
268	    owner: "space",
269	    category: isQa ? "客服运营" : isPolicy ? "知识问答" : isContract ? "法务" : "业务流程",
270	    status: "草稿",
271	    version: "v0.1.0",
272	    creator: "jingxiu.zhao",
273	    updatedAt: "刚刚",
274	    agents: 0,
275	    assets: ["SKILL.md", "manifest.json", "input.schema.json", "output.schema.json", "examples/happy_path.md"],
276	    tags: ["生成", isQa ? "客服" : isPolicy ? "政策" : "流程"],
277	    scan: { level: "-", issues: 0, result: "未扫描", time: "-" },
278	    content: buildNLPContent(text, output),
279	    files: {
280	      "SKILL.md": buildNLPContent(text, output),
281	      "manifest.json": bundleFileTemplate("manifest.json"),
282	      "input.schema.json": bundleFileTemplate("input.schema.json"),
283	      "output.schema.json": bundleFileTemplate("output.schema.json"),
284	      "examples/happy_path.md": bundleFileTemplate("examples/happy_path.md")
285	    }
286	  };
287	}
