328	export function validateImportFile(filename, size) {
329	  const name = String(filename || "");
330	  const allowedExts = [".md", ".json", ".yaml", ".yml", ".zip"];
331	  const ext = name.slice(name.lastIndexOf(".")).toLowerCase();
332	  if (!ext || !allowedExts.includes(ext)) {
333	    return { valid: false, error: "仅支持 .md、.json、.yaml、.yml、.zip 格式" };
334	  }
335	  const maxSize = 10 * 1024 * 1024; // 10MB
336	  if (size > maxSize) {
337	    return { valid: false, error: "文件大小不能超过 10MB" };
338	  }
339	  const dangerousExts = [".exe", ".sh", ".bat", ".cmd", ".ps1", ".vbs", ".jar", ".py", ".rb"];
340	  if (dangerousExts.includes(ext)) {
341	    return { valid: false, error: "不允许上传可执行脚本或程序文件" };
342	  }
343	  return { valid: true, error: "" };
344	}
