346	export function scanSkill(skill) {
347	  const content = `${getSkillContent(skill) || ""} ${skill.description || ""}`;
348	  const findings = [];
349	
350	  const check = (label, patterns, hitLabel, description, fix) => {
351	    for (const pattern of patterns) {
352	      const match = content.match(pattern);
353	      if (match) {
354	        const snippet = (match[0] || "").slice(0, 50);
355	        findings.push({
356	          dimension: label,
357	          level: hitLabel,
358	          location: skill.assets?.find(a => a.endsWith(".md") || a.endsWith(".json") || a.endsWith(".yaml")) || "SKILL.md",
359	          detail: description,
360	          match: snippet,
361	          suggestion: fix
362	        });
363	      }
364	    }
365	  };
366	
367	  check("敏感凭证", [/api\s*key/i, /token/i, /密码/, /私钥/, /secret/i, /access_key/i], "高", "检测到疑似敏感凭证", "使用平台变量或安全引用替换明文凭证，参考安全配置文档");
368	  check("提示词注入", [/忽略.*指令/, /忽略.*规则/, /override.*instruction/i, /ignore.*prompt/i, /system.*message/i], "高", "检测到可能的提示词注入风险", "移除覆盖系统指令的语句，采用白名单机制限制输入范围");
369	  check("危险操作", [/删除文件/, /subprocess/i, /os\.system/i, /exec/i, /eval/i, /fs\.unlink/i, /rm\s+-rf/i], "高", "检测到危险操作指令", "移除直接调用系统命令或文件删除的指令，改用平台提供的安全 API");
370	  check("网络风险", [/外网发送/, /169\.254/, /curl/i, /fetch.*http/i, /request.*http/i, /axios/i], "中", "检测到外部网络请求", "声明网络访问需求并限制目标域名，或使用平台网络代理");
371	  check("数据泄露", [/日志.*输出/, /console\.log/, /print\s*\(/, /write.*file/i, /上传/, /导出.*数据/], "中", "检测到可能的数据泄露操作", "限制数据输出范围，避免将用户数据写入外部存储");
372	  check("依赖风险", [/require\(/, /import\s+/, /from\s+['"]/, /npm install/i, /pip install/i], "低", "检测到外部依赖引用", "声明外部依赖并提供校验和来源，使用平台依赖管理");
373	  check("结构冲突", [/\/input[\s\S]*\/input/, /\/output[\s\S]*\/output/, /\/constraints[\s\S]*\/constraints/], "中", "检测到声明块重复定义", "移除重复声明块，合并内容到唯一块中");
374	  check("生成质量风险", [/大约/, /大概/, /maybe/i, /perhaps/i, /可能/, /应该/, /不确定/], "低", "检测到模糊表述可能影响生成质量", "使用精确表述替换模糊词语，定义明确的行为边界");
375	
376	  if (findings.length) {
377	    const highCount = findings.filter(f => f.level === "高").length;
378	    const midCount = findings.filter(f => f.level === "中").length;
379	    const lowCount = findings.filter(f => f.level === "低").length;
380	    const level = highCount > 0 ? "高" : midCount > 0 ? "中" : "低";
381	    return {
382	      summary: { status: "扫描失败", level, passed: false },
383	      scan: {
384	        level,
385	        issues: findings.length,
386	        highCount,
387	        midCount,
388	        lowCount,
389	        result: "不通过",
390	        time: new Date().toLocaleString("zh-CN", { hour12: false })
391	      },
392	      findings
393	    };
394	  }
395	  return {
396	    summary: { status: "已发布", level: "低", passed: true },
397	    scan: {
398	      level: "低",
399	      issues: 0,
400	      highCount: 0,
401	      midCount: 0,
402	      lowCount: 0,
403	      result: "通过",
404	      time: new Date().toLocaleString("zh-CN", { hour12: false })
405	    },
406	    findings: [{ dimension: "全部检查项", level: "低", location: "-", detail: "结构化声明块完整，未发现高风险内容", match: "", suggestion: "" }]
407	  };
408	}
