410	export function getNextStatus(status, action) {
411	  const transitions = {
412	    "草稿:request_publish": "扫描中",
413	    "草稿变更:request_publish": "扫描中",
414	    "扫描失败:request_publish": "扫描中",
415	    "已下架:request_publish": "扫描中",
416	    "扫描中:scan_pass": "已发布",
417	    "扫描中:scan_fail": "扫描失败",
418	    "已发布:unpublish": "已下架"
419	  };
420	  const next = transitions[`${status}:${action}`];
421	  if (!next) throw new Error(`状态 ${status} 不允许执行 ${action}`);
422	  return next;
423	}
