425	export function filterSkills(skills, filters = {}) {
426	  const keyword = String(filters.keyword || "").trim().toLowerCase();
427	  return skills.filter(skill => {
428	    const inLibrary = filters.library === "official" ? skill.owner === "official" : skill.owner === "space";
429	    const matchesKeyword = !keyword || [skill.name, skill.skillId, skill.description, skill.category, ...(skill.tags || [])]
430	      .join(" ")
431	      .toLowerCase()
432	      .includes(keyword);
433	    const matchesStatus = !filters.status || filters.status === "全部" || skill.status === filters.status;
434	    const matchesSource = !filters.source || filters.source === "全部" || skill.source === filters.source;
435	    return inLibrary && matchesKeyword && matchesStatus && matchesSource;
436	  });
437	}
