test("seedSkills publishLogs/auditHistory/operationLogs structure", () => {
  const published = seedSkills.find(s => s.id === "sk-001");
  const draft = seedSkills.find(s => s.id === "sk-004");
  const failed = seedSkills.find(s => s.id === "sk-003");

  // sk-001 (published) should have arrays with data
  assert.ok(Array.isArray(published.publishLogs), "sk-001 publishLogs should be array");
  assert.ok(published.publishLogs.length >= 2, "sk-001 publishLogs should have >= 2 entries");
  assert.ok(published.publishLogs[0].version, "publishLogs entry should have version");
  assert.ok(published.publishLogs[0].publisher, "publishLogs entry should have publisher");
  assert.ok(published.publishLogs[0].time, "publishLogs entry should have time");
  assert.ok(published.publishLogs[0].note, "publishLogs entry should have note");
  assert.ok(published.publishLogs[0].auditSummary, "publishLogs entry should have auditSummary");

  assert.ok(Array.isArray(published.auditHistory), "sk-001 auditHistory should be array");
  assert.ok(published.auditHistory.length >= 2, "sk-001 auditHistory should have >= 2 entries");
  assert.ok(published.auditHistory[0].time, "auditHistory entry should have time");
  assert.ok(published.auditHistory[0].result, "auditHistory entry should have result");
  assert.ok(published.auditHistory[0].level, "auditHistory entry should have level");
  assert.ok(published.auditHistory[0].issues !== undefined, "auditHistory entry should have issues");
  assert.ok(published.auditHistory[0].version, "auditHistory entry should have version");

  assert.ok(Array.isArray(published.operationLogs), "sk-001 operationLogs should be array");
  assert.ok(published.operationLogs.length >= 4, "sk-001 operationLogs should have >= 4 entries");
  assert.ok(published.operationLogs[0].time, "operationLogs entry should have time");
  assert.ok(published.operationLogs[0].action, "operationLogs entry should have action");
  assert.ok(published.operationLogs[0].operator, "operationLogs entry should have operator");

  // sk-004 (draft) should have empty publishLogs and auditHistory, 1 operationLog
  assert.deepEqual(draft.publishLogs, [], "sk-004 publishLogs should be empty");
  assert.deepEqual(draft.auditHistory, [], "sk-004 auditHistory should be empty");
  assert.equal(draft.operationLogs.length, 1, "sk-004 should have 1 operationLog");

  // sk-003 (scan failed) should have 1+ entries for each
  assert.ok(failed.auditHistory.length >= 1, "sk-003 should have audit history");
  assert.equal(failed.auditHistory[0].result, "不通过", "sk-003 first audit result should be 不通过");
  assert.ok(failed.publishLogs.length >= 1, "sk-003 should have publish logs");
  assert.ok(failed.operationLogs.length >= 2, "sk-003 should have >= 2 operation logs");
});

