/* ---- Asset file tree ---- */
.asset-file-tree {
  display: grid;
  gap: 4px;
}
.asset-category {
  margin-bottom: 14px;
}
.asset-category:last-child {
  margin-bottom: 0;
}
.asset-category-label {
  font-size: 12px;
  font-weight: 650;
  color: var(--muted);
  margin-bottom: 6px;
  padding: 0 2px;
}
.asset-category-items {
  display: grid;
  gap: 5px;
}
.asset-file-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 8px 10px;
  border: 1px solid var(--line);
  border-radius: var(--radius-sm);
  background: #f8fafc;
}
.asset-filename {
  font-family: ui-monospace, SFMono-Regular, Menlo, monospace;
  font-size: 12px;
  color: var(--text);
}
.asset-filesize {
  font-size: 11px;
  color: var(--subtle);
  font-variant-numeric: tabular-nums;
}

/* ---- Operation tag colors ---- */
.operation-tag {
  display: inline-block;
  padding: 2px 8px;
  border-radius: 999px;
  font-size: 11px;
  font-weight: 600;
  white-space: nowrap;
}
.operation-tag.create { color: var(--blue); background: var(--blue-soft); }
.operation-tag.edit { color: var(--orange); background: #fff7ed; }
.operation-tag.generate { color: #9b4dff; background: #faf5ff; }
.operation-tag.publish { color: var(--green); background: #ecfdf5; }
.operation-tag.unpublish { color: var(--red); background: #fff1f2; }
.operation-tag.delete { color: var(--red); background: #fff1f2; }

/* ---- Log timeline ---- */
.log-timeline {
  display: grid;
  gap: 0;
}
.log-entry {
  display: grid;
  grid-template-columns: 140px 20px 1fr;
  gap: 12px;
  padding: 10px 0;
  border-bottom: 1px solid var(--line);
  align-items: center;
}
.log-entry:last-child {
  border-bottom: 0;
}
.log-time {
  color: var(--muted);
  font-size: 12px;
  text-align: right;
}
.log-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: var(--blue);
  justify-self: center;
  flex-shrink: 0;
}
.log-body {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-wrap: wrap;
}
.log-operator {
  color: var(--text);
  font-size: 13px;
}
.log-detail {
  color: var(--muted);
  font-size: 12px;
}

